settings.liquid:
{% comment %}
  Hockey Name Generator – responsive iframe embed
  Source: https://hocky-name-generator-seven.vercel.app/
{% endcomment %}

<style>
  .responsive-iframe-container {
    position: relative;
    width: 100%;
    padding-top: 56.25%; /* 16:9 aspect ratio */
  }
  .responsive-iframe-container iframe {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    border: 0;
  }
</style>

<div class="responsive-iframe-container">
  <iframe
    src="https://hocky-name-generator-seven.vercel.app/"
    title="Hockey Name Generator"
    loading="lazy"
    allow="clipboard-write; encrypted-media; picture-in-picture"
  ></iframe>
</div>
